sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.loading = false;
    c.filterStatus = c.data.currentFilter || 'all';
    c.rejectingEvent = null;
    c.rejectionReason = '';

    c.approveEvent = function(event) {
        if (c.loading) return;
        c.loading = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'approve_event',
            event_id: event.sys_id
        }).then(function(r) {
            c.data = r.data;
            c.loading = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.loading = false;
        });
    };

    c.rejectEvent = function(event) {
        if (c.loading) return;
        if (!c.rejectionReason) {
            c.data.errorMsg = 'Please provide a rejection reason.';
            return;
        }
        c.loading = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'reject_event',
            event_id: event.sys_id,
            reason: c.rejectionReason
        }).then(function(r) {
            c.data = r.data;
            c.rejectingEvent = null;
            c.rejectionReason = '';
            c.loading = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.loading = false;
        });
    };

    c.toggleRejectForm = function(event) {
        if (c.rejectingEvent === event.sys_id) {
            c.rejectingEvent = null;
            c.rejectionReason = '';
        } else {
            c.rejectingEvent = event.sys_id;
            c.rejectionReason = '';
        }
    };

    c.applyFilter = function() {
        if (c.loading) return;
        c.loading = true;
        c.data.successMsg = '';
        c.data.errorMsg = '';

        c.server.get({
            action: 'filter',
            status: c.filterStatus
        }).then(function(r) {
            c.data = r.data;
            c.loading = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.loading = false;
        });
    };
};

sp_widget.css:
.sp-college-events .sp-panel {
    border: 1px solid $border-tertiary;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
}
.sp-college-events .sp-panel .panel-heading {
    background: $background-secondary;
    border-bottom: 1px solid $border-tertiary;
    padding: 12px 15px;
}
.sp-college-events .sp-panel .panel-title {
    font-size: 16px;
    font-weight: 600;
    color: $text-color;
    margin: 0;
    line-height: 30px;
}
.sp-college-events .filter-label {
    margin-right: 8px;
    font-weight: 500;
    color: $text-muted;
}
.sp-college-events .sp-panel .table th {
    color: $text-muted;
    font-weight: 600;
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border-bottom: 2px solid $border-tertiary;
}
.sp-college-events .sp-panel .table td {
    vertical-align: middle;
    color: $text-color;
}
.sp-college-events .empty-state {
    padding: 40px 20px;
}
.sp-college-events .empty-icon {
    font-size: 48px;
    color: $text-muted;
    display: block;
    margin-bottom: 12px;
}
.sp-college-events .reject-form-row {
    background: $state-warning-bg;
}
.sp-college-events .reject-form {
    padding: 10px 0;
}
.sp-college-events .reject-form label {
    font-weight: 600;
    color: $text-color;
    margin-bottom: 6px;
    display: block;
}
.sp-college-events .reject-form textarea {
    margin-bottom: 10px;
}
.sp-college-events .reject-actions {
    display: flex;
    gap: 8px;
}

sp_widget.script:
(function() {
    data.events = [];
    data.message = '';
    data.successMsg = '';
    data.errorMsg = '';
    data.isCollegeAdmin = false;
    data.currentFilter = 'all';

    try {
        var userId = gs.getUserID();

        // Get the current user's college
        var userGr = new GlideRecord('sys_user');
        userGr.setLimit(1);
        if (!userGr.get(userId)) {
            data.message = 'Unable to identify current user.';
            return;
        }

        var collegeId = userGr.getValue('u_college') + '';
        if (!collegeId || collegeId === 'null' || collegeId === '') {
            data.message = 'You are not assigned to a college.';
            return;
        }

        data.isCollegeAdmin = true;

        // Handle approve event action
        if (input && input.action === 'approve_event') {
            var approveGr = new GlideRecord('x_2097092_linq_event');
            approveGr.setLimit(1);
            if (approveGr.get(input.event_id)) {
                // Verify event belongs to this college
                if (approveGr.getValue('college') + '' === collegeId) {
                    approveGr.setValue('status', 'approved');
                    approveGr.setValue('approved_by', userId);
                    approveGr.setValue('approved_on', new GlideDateTime());
                    approveGr.update();
                    data.successMsg = 'Event "' + (approveGr.getValue('title') + '') + '" has been approved.';
                } else {
                    data.errorMsg = 'You do not have permission to approve this event.';
                }
            } else {
                data.errorMsg = 'Event not found.';
            }
        }

        // Handle reject event action
        if (input && input.action === 'reject_event') {
            var rejectGr = new GlideRecord('x_2097092_linq_event');
            rejectGr.setLimit(1);
            if (rejectGr.get(input.event_id)) {
                // Verify event belongs to this college
                if (rejectGr.getValue('college') + '' === collegeId) {
                    rejectGr.setValue('status', 'draft');
                    rejectGr.setValue('rejection_reason', input.reason || '');
                    rejectGr.update();
                    data.successMsg = 'Event "' + (rejectGr.getValue('title') + '') + '" has been rejected.';
                } else {
                    data.errorMsg = 'You do not have permission to reject this event.';
                }
            } else {
                data.errorMsg = 'Event not found.';
            }
        }

        // Determine filter status
        var filterStatus = 'all';
        if (input && input.action === 'filter' && input.status) {
            filterStatus = input.status;
        }
        data.currentFilter = filterStatus;

        // Get events for this college
        var evGr = new GlideRecord('x_2097092_linq_event');
        evGr.addQuery('college', collegeId);
        if (filterStatus !== 'all') {
            evGr.addQuery('status', filterStatus);
        }
        evGr.orderByDesc('event_date');
        evGr.setLimit(100);
        evGr.query();

        while (evGr.next()) {
            var eventId = evGr.getUniqueValue();

            // Count registrations for this event
            var regCount = 0;
            var regGa = new GlideAggregate('x_2097092_linq_registration');
            regGa.addQuery('event', eventId);
            regGa.addAggregate('COUNT');
            regGa.query();
            if (regGa.next()) {
                regCount = parseInt(regGa.getAggregate('COUNT'), 10) || 0;
            }

            data.events.push({
                sys_id: eventId,
                title: evGr.getValue('title') + '',
                club_name: evGr.getDisplayValue('club') + '',
                event_date: evGr.getDisplayValue('event_date') + '',
                status: evGr.getValue('status') + '',
                venue: evGr.getValue('venue') + '',
                registrations: regCount
            });
        }
    } catch (e) {
        gs.error('linq-admin-college-events error: ' + e.message);
        data.errorMsg = 'An error occurred loading events.';
    }
})();
